def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(2, a + 5):
                    term = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    priority += term * np.sin(ratio * b / (a + 2)) * np.exp(-b / (ratio + 0.1))
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.sqrt(bin_cap) * np.cos(ratio * 5)
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 4):
                    val = ((ratio - c) ** 4) * np.tanh(ratio * c) / (d + 1)
                    priority += np.tanh(val) * 1.4
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 4) * 3
            if (i * 2) % 5 == 0:
                priority *= np.cos(ratio * 3)
            else:
                priority /= (np.sqrt(bin_cap) + 1.2)
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 1.5) * np.sin(e * ratio * 1.1)
                if e % 3 == 0:
                    s -= np.cos(e * ratio / 2)
            priority = (s * np.cos(10 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap < item:
                priority += np.exp(-ratio) * 3
            else:
                priority -= np.sqrt(item / (bin_cap + 0.1)) * 2
        elif 1 <= ratio < 2:
            s = 0
            for f in range(1, 20):
                s += ((2 - ratio) ** f) / (f ** 1.5 + 0.7) * np.cos(f * ratio * 0.8)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.03))
            for g in range(1, 6):
                priority += np.sin(g * ratio * (i + 1)) * ((ratio - 1) ** g) / (g * 1.1)
            if i % 2 == 0:
                priority += np.tanh(ratio * i) * 1.1
            else:
                priority -= np.sin(ratio * i) * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 18):
                s += ((1 - ratio) ** h) / (h * 3) * np.sin(h * item * 1.3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.8)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.7) * 0.9
            if bin_cap < item * 0.7:
                priority += np.log1p(bin_cap + item * 2) * 3
            else:
                priority -= np.exp(-ratio * 2.2) * 5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 16):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 3 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 8) * np.sin(item * m * 1.4)
            if i % 4 == 0:
                priority += np.tanh(ratio * i * 2) * 1.2
            else:
                priority -= np.sin(ratio * i * 2) * 1.2
        else:
            s = 0
            for n in range(1, 20):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for o in range(1, 10):
                priority += ((0.2 - ratio) ** o) / (o * 9) * np.cos(item * o)
        if bin_cap < item * 0.4:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for z in range(1, 6):
            if (i + z) % 5 == 0:
                priority += np.sin(ratio * (i + z) * 1.5) * 0.4
            else:
                priority -= np.cos(ratio * (i + z) * 1.5) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
